import { NextRequest } from "next/server";
import { cloudinary } from "@workspace/backend/modules/cloudinary/cloudinary.client";

type Variant = "thumb" | "large" | "original";

function getTransformation(variant: Variant): string {
  switch (variant) {
    case "thumb":
      return "w_128,h_128,c_fit,f_auto,q_auto";
    case "large":
      return "w_1024,h_1024,c_fit,f_auto,q_auto";
    case "original":
    default:
      return "f_auto,q_auto";
  }
}

function isValidVariant(value: string | null): value is Variant {
  return value === "thumb" || value === "large" || value === "original";
}

export async function GET(
  req: NextRequest,
  context: { params: { publicId?: string[] } }
): Promise<Response> {
  const { params } = context;

  if (!params?.publicId?.length) {
    return new Response("Missing publicId", { status: 400 });
  }

  const publicId = params.publicId.join("/");

  const rawVariant = req.nextUrl.searchParams.get("variant");
  const variant: Variant = isValidVariant(rawVariant) ? rawVariant : "thumb";

  const transformation = getTransformation(variant);

  const url = cloudinary.url(publicId, {
    secure: true,
    type: "authenticated",
    transformation,
  });

  return Response.redirect(url);
}